
(function() {
  const b64Data = '';
  const jsonStr = atob(b64Data);
  const data = JSON.parse(jsonStr);
  localStorage.setItem('METER_DATA', jsonStr);
  window.METER_DATA = data;
  console.log('✅ Injected restructured METER_DATA');
  console.log('Rooms months:', Object.keys(data.rooms || {}).length);
})();
